    // Add these lines
    override fun onStart() { 
        super.onStart()
        val view = window.findViewById<ViewGroup>(FLUTTER_VIEW_ID).getChildAt(0) as FlutterSurfaceView
        if(view.parent is FlutterView){
            val pview = view.parent as FlutterView;
            // 
            pview.requestFocus()
            view.requestFocus()
        }
    }
